package cli

import (
	"fmt"
	"os"
	"path/filepath"

	"github.com/jdbencardinop/tesseraspaces/internal"
)

func Add(args []string) {
	if len(args) < 1 {
		println("Usage: ts add <feature>")
		return
	}

	feature := args[0]
	root := internal.FeaturePath(feature)

	// Ensure .ts-workspace marker exists in workspace root
	wsRoot := internal.TsRoot()
	internal.Must(os.MkdirAll(filepath.Join(wsRoot, ".ts-workspace"), 0755))

	// TODO: make worktress a constant in internal package
	internal.Must(os.MkdirAll(filepath.Join(root, "worktrees"), 0755))

	// TODO: either add a slug arg or pass the entire feature description and slugify it here
	internal.Must(os.WriteFile(filepath.Join(root, "FEATURE.md"), []byte("# "+feature+"\n"), 0644))

	// TODO: Add a template for other files, here we just create a CLAUDE.local.md file
	internal.Must(os.WriteFile(filepath.Join(root, "CLAUDE.local.md"), []byte("# "+feature+" - CLAUDE shared context\n"), 0644))

	fmt.Println("Feature added:", feature)
}

package internal

import (
	"fmt"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

func MainRepoRoot() (string, error) {
	// git-common-dir returns the .git dir of the main repo even from a worktree.
	// In a non-worktree checkout it returns ".git" (relative).
	out, err := exec.Command("git", "rev-parse", "--git-common-dir").Output()
	if err != nil {
		return "", err
	}
	gitDir := strings.TrimSpace(string(out))

	if gitDir == ".git" {
		// Not inside a worktree — fall back to normal detection.
		return RepoRoot()
	}

	// gitDir is absolute (e.g. /path/to/repo/.git), resolve to parent.
	return filepath.Dir(filepath.Clean(gitDir)), nil
}

func RepoRoot() (string, error) {
	out, err := exec.Command("git", "rev-parse", "--show-toplevel").Output()
	if err != nil {
		return "", err
	}
	return strings.TrimSpace(string(out)), nil
}

func Run(name string, args ...string) error {
	cmd := exec.Command(name, args...)
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	cmd.Stdin = os.Stdin

	return cmd.Run()
}

func RunDir(dir string, name string, args ...string) error {
	cmd := exec.Command(name, args...)
	cmd.Stdout = os.Stdout
	cmd.Stderr = os.Stderr
	cmd.Stdin = os.Stdin
	cmd.Dir = dir

	return cmd.Run()
}

func Must(err error) {
	if err != nil {
		fmt.Println("Error:", err)
		os.Exit(1)
	}
}

package internal

import (
	"os"
	"path/filepath"
	"strings"
)

const workspaceMarker = ".ts-workspace"

// DetectWorkspaceRoot checks if cwd is inside an existing workspace.
// Returns the workspace root or empty string.
func DetectWorkspaceRoot(cwd string, cfg Config) string {
	// Tier 1: Walk up looking for .ts-workspace marker
	dir := cwd
	for {
		if _, err := os.Stat(filepath.Join(dir, workspaceMarker)); err == nil {
			return dir
		}
		parent := filepath.Dir(dir)
		if parent == dir {
			break
		}
		dir = parent
	}

	// Tier 2: Check if cwd is inside any configured workspace path
	for _, ws := range cfg.Workspaces {
		absWs, err := filepath.Abs(ws)
		if err != nil {
			continue
		}
		absCwd, err := filepath.Abs(cwd)
		if err != nil {
			continue
		}
		if strings.HasPrefix(absCwd, absWs+string(filepath.Separator)) || absCwd == absWs {
			return absWs
		}
	}

	// Tier 3: Check if cwd is inside ~/ts
	home, _ := os.UserHomeDir()
	globalDefault := filepath.Join(home, "ts")
	absCwd, _ := filepath.Abs(cwd)
	if strings.HasPrefix(absCwd, globalDefault+string(filepath.Separator)) || absCwd == globalDefault {
		return globalDefault
	}

	return ""
}

// resolveTsRoot contains the resolution logic with injectable dependencies.
func resolveTsRoot(envRoot string, cwd string, repoRoot string, repoErr error, cfg Config) string {
	// 0. TS_ROOT env var — always wins
	if envRoot != "" {
		return envRoot
	}

	// 1. Already inside a workspace? Return that root.
	if wsRoot := DetectWorkspaceRoot(cwd, cfg); wsRoot != "" {
		return wsRoot
	}

	// 2. Global config keyed by repo path
	if repoErr == nil {
		if ws, ok := cfg.Workspaces[repoRoot]; ok {
			return ws
		}

		// 3. Repo-relative sibling: ../<repo-name>.ts/
		repoName := filepath.Base(repoRoot)
		return filepath.Join(filepath.Dir(repoRoot), repoName+".ts")
	}

	// 4. Global fallback
	home, _ := os.UserHomeDir()
	return filepath.Join(home, "ts")
}

func TsRoot() string {
	repoRoot, repoErr := MainRepoRoot()
	cfg := LoadConfig()
	cwd, _ := os.Getwd()
	return resolveTsRoot(os.Getenv("TS_ROOT"), cwd, repoRoot, repoErr, cfg)
}

func FeaturePath(feature string) string {
	return filepath.Join(TsRoot(), feature)
}

func WorktreePath(feature, branch string) string {
	return filepath.Join(FeaturePath(feature), "worktrees", branch)
}

package internal

import (
	"errors"
	"os"
	"path/filepath"
	"testing"
)

func TestResolveTsRoot_EnvVar(t *testing.T) {
	got := resolveTsRoot("/custom/root", "/somewhere", "/some/repo", nil, Config{})
	if got != "/custom/root" {
		t.Errorf("expected /custom/root, got %s", got)
	}
}

func TestResolveTsRoot_ConfigEntry(t *testing.T) {
	cfg := Config{Workspaces: map[string]string{
		"/Users/me/projects/myapp": "/data/workspaces/myapp",
	}}
	got := resolveTsRoot("", "/somewhere", "/Users/me/projects/myapp", nil, cfg)
	if got != "/data/workspaces/myapp" {
		t.Errorf("expected /data/workspaces/myapp, got %s", got)
	}
}

func TestResolveTsRoot_RepoSibling(t *testing.T) {
	got := resolveTsRoot("", "/somewhere", "/Users/me/projects/myapp", nil, Config{})
	want := "/Users/me/projects/myapp.ts"
	if got != want {
		t.Errorf("expected %s, got %s", want, got)
	}
}

func TestResolveTsRoot_Fallback(t *testing.T) {
	got := resolveTsRoot("", "/somewhere", "", errors.New("not a repo"), Config{})
	home, _ := os.UserHomeDir()
	want := filepath.Join(home, "ts")
	if got != want {
		t.Errorf("expected %s, got %s", want, got)
	}
}

func TestResolveTsRoot_EnvWinsOverConfig(t *testing.T) {
	cfg := Config{Workspaces: map[string]string{
		"/some/repo": "/configured/path",
	}}
	got := resolveTsRoot("/env/override", "/somewhere", "/some/repo", nil, cfg)
	if got != "/env/override" {
		t.Errorf("env should win, got %s", got)
	}
}

func TestResolveTsRoot_ConfigWinsOverSibling(t *testing.T) {
	cfg := Config{Workspaces: map[string]string{
		"/Users/me/projects/myapp": "/explicit/path",
	}}
	got := resolveTsRoot("", "/somewhere", "/Users/me/projects/myapp", nil, cfg)
	if got != "/explicit/path" {
		t.Errorf("config should win over sibling, got %s", got)
	}
}

func TestFeaturePath(t *testing.T) {
	root := resolveTsRoot("/ws", "/somewhere", "", errors.New("no repo"), Config{})
	want := "/ws/auth"
	got := filepath.Join(root, "auth")
	if got != want {
		t.Errorf("expected %s, got %s", want, got)
	}
}

func TestWorktreePath(t *testing.T) {
	root := resolveTsRoot("/ws", "/somewhere", "", errors.New("no repo"), Config{})
	want := "/ws/auth/worktrees/login-fix"
	got := filepath.Join(root, "auth", "worktrees", "login-fix")
	if got != want {
		t.Errorf("expected %s, got %s", want, got)
	}
}

// --- Workspace detection tests ---

func TestDetectWorkspaceRoot_MarkerFile(t *testing.T) {
	tmp := t.TempDir()
	wsRoot := filepath.Join(tmp, "myapp.ts")
	nested := filepath.Join(wsRoot, "auth", "worktrees", "branch-a")
	os.MkdirAll(filepath.Join(wsRoot, ".ts-workspace"), 0755)
	os.MkdirAll(nested, 0755)

	got := DetectWorkspaceRoot(nested, Config{})
	if got != wsRoot {
		t.Errorf("expected %s, got %s", wsRoot, got)
	}
}

func TestDetectWorkspaceRoot_ConfigMatch(t *testing.T) {
	tmp := t.TempDir()
	wsRoot := filepath.Join(tmp, "custom-workspace")
	nested := filepath.Join(wsRoot, "feature", "worktrees", "branch")
	os.MkdirAll(nested, 0755)

	cfg := Config{Workspaces: map[string]string{
		"/some/repo": wsRoot,
	}}
	got := DetectWorkspaceRoot(nested, cfg)
	if got != wsRoot {
		t.Errorf("expected %s, got %s", wsRoot, got)
	}
}

func TestDetectWorkspaceRoot_GlobalDefault(t *testing.T) {
	home, _ := os.UserHomeDir()
	globalDefault := filepath.Join(home, "ts")

	// Only test if ~/ts exists or we can create it temporarily
	nested := filepath.Join(globalDefault, "some-feature")
	if _, err := os.Stat(globalDefault); os.IsNotExist(err) {
		os.MkdirAll(nested, 0755)
		defer os.RemoveAll(globalDefault)
	} else {
		os.MkdirAll(nested, 0755)
		defer os.Remove(nested)
	}

	got := DetectWorkspaceRoot(nested, Config{})
	if got != globalDefault {
		t.Errorf("expected %s, got %s", globalDefault, got)
	}
}

func TestDetectWorkspaceRoot_NoMatch(t *testing.T) {
	got := DetectWorkspaceRoot("/some/random/path", Config{})
	if got != "" {
		t.Errorf("expected empty string, got %s", got)
	}
}

func TestResolveTsRoot_WorkspaceDetectionWins(t *testing.T) {
	tmp := t.TempDir()
	wsRoot := filepath.Join(tmp, "myapp.ts")
	cwd := filepath.Join(wsRoot, "auth", "worktrees", "branch-a")
	os.MkdirAll(filepath.Join(wsRoot, ".ts-workspace"), 0755)
	os.MkdirAll(cwd, 0755)

	// Even with a repo configured, workspace detection should win (after env)
	got := resolveTsRoot("", cwd, "/some/repo", nil, Config{})
	if got != wsRoot {
		t.Errorf("workspace detection should win, expected %s, got %s", wsRoot, got)
	}
}
